// Mapping of numbers to field names
const mapping = {
  1: "Concrete",
  2: "Existing Coating/Resin",
  3: "Tiles",
  4: "Timber"
};
const valueString = $('Router 1').first().json.value

if (!valueString || !valueString.trim()) {
  return { json: { mappedValues: [] } };
}
const numbers = valueString
  .split(',')
  .map(v => v.trim())
  .map(v => parseInt(v, 10))
  .filter(n => !isNaN(n));

const mappedValues = numbers.map(n => mapping[n]).filter(Boolean);

return { json: { mappedValues } };

