return $input.all().map(item => {
  const row = item.json;

  let projectDetails = row['Project Details'] || '';

  if (Array.isArray(projectDetails)) {
    projectDetails = projectDetails.join(', ');
  } else if (typeof projectDetails === 'string') {
    try {
      const parsed = JSON.parse(projectDetails);
      if (Array.isArray(parsed)) {
        projectDetails = parsed.join(', ');
      }
    } catch (e) {}
  }

  // Helper to add only non-empty fields
  const addField = (label, value) => {
    if (value && value.toString().trim() !== '') {
      return `${label}: ${value}`;
    }
    return null;
  };

  const lines = [
    "Thanks! Here’s what I’ve got:",
    "",
    addField("Service", row.Flooring),
    addField("Location", row.Location),
    addField("Size", row['Project Size']),
    addField("Current surface", projectDetails),
    addField("Other surface", row['Project Details Other']),
    addField("Name", row['Full Name']),
    addField("Email", row['Email Address']),
    addField("Phone", row.Phone_Number),
    addField("Company", row.Company),
    addField("Contact method", row['Preferred Contact'])
  ].filter(Boolean); // removes nulls

  const bodyText = lines.join("\\n");

  return {
    json: {
      wa_id: row.Phone.toString(),
      whatsappBody: bodyText
    }
  };
});

