return $input.all().map(item => {
  let outputObj = {};

  try {
    let raw = item.json.output;

    if (typeof raw === "string") {
      // Remove markdown code block formatting
      raw = raw.replace(/```json|```/g, "").trim();

      // Parse string into object
      outputObj = JSON.parse(raw);
    } else {
      outputObj = raw || {};
    }

  } catch (err) {
    outputObj = {};
  }

  return {
    json: {
      intent: outputObj.intent || "other",
      field: outputObj.field || "null",
      value: outputObj.value || "",
      phone: outputObj.user_phone
    }
  };
});

const data = $('Format Data').first().json;

// Convert literal \n into HTML line breaks
let message = data.whatsappBody
  .replace(/\\n/g, '<br>')
  .trim();

// Optional: wrap in simple clean HTML container
const htmlBody = `
<div style="font-family: Arial, sans-serif; font-size: 14px; line-height: 1.6;">
  ${message}
</div>
`;

return [
  {
    json: {
      html: htmlBody,
    }
  }
];
